import{_ as a,o as t,c as o,a2 as s}from"./chunks/framework.DTa47_fH.js";const u=JSON.parse('{"title":"PowerBI Desktop authoring guide -- swao-portfolio.pbit","description":"","frontmatter":{},"headers":[],"relativePath":"templates/AUTHORING-GUIDE-PORTFOLIO.md","filePath":"templates/AUTHORING-GUIDE-PORTFOLIO.md"}'),i={name:"templates/AUTHORING-GUIDE-PORTFOLIO.md"};function n(d,e,r,p,l,c){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="powerbi-desktop-authoring-guide-swao-portfolio-pbit" tabindex="-1">PowerBI Desktop authoring guide -- <code>swao-portfolio.pbit</code> <a class="header-anchor" href="#powerbi-desktop-authoring-guide-swao-portfolio-pbit" aria-label="Permalink to &quot;PowerBI Desktop authoring guide -- \`swao-portfolio.pbit\`&quot;">​</a></h1><blockquote><p><strong>This guide is for consultants who want to customise or rebuild the portfolio template.</strong> If you just want to open the template and load your data, see <a href="/how-it-works#powerbi-dashboards">How it works -- PowerBI dashboards</a> instead. Your template is at <code>wsp/templates/powerbi/swao-portfolio.pbit</code>.</p></blockquote><p>The portfolio template is a separate <code>.pbit</code> from the single-app one, not an extension of it. Portfolio assessments (multiple apps in one workspace) use <code>swao-portfolio.pbit</code>; single-app assessments use <code>swao-report.pbit</code>.</p><hr><h2 id="v1-3-update-master-detail-pattern-per-app-evidence-urls-rag-palette" tabindex="-1">v1.3 update -- master/detail pattern, per-app evidence URLs, RAG palette <a class="header-anchor" href="#v1-3-update-master-detail-pattern-per-app-evidence-urls-rag-palette" aria-label="Permalink to &quot;v1.3 update -- master/detail pattern, per-app evidence URLs, RAG palette&quot;">​</a></h2><p>Sprint 030 #0250 + #0251 + #0269 retrofitted the swao-report v1.5 master/detail pattern across the portfolio template. The pattern + the portfolio-specific differences from swao-report are documented in <code>AUTHORING-GUIDE.md</code> Â§6 (master/detail recipe is identical) with two adaptations called out below.</p><h3 id="adaptation-a-portfolio-relationships-must-be-m-m" tabindex="-1">Adaptation A -- portfolio relationships must be M:M <a class="header-anchor" href="#adaptation-a-portfolio-relationships-must-be-m-m" aria-label="Permalink to &quot;Adaptation A -- portfolio relationships must be M:M&quot;">​</a></h3><p>In a single-app bundle, <code>fact_controls[control_id]</code> is unique per row. In a portfolio bundle, the same <code>control_id</code> (e.g. <code>GDPR_Art_5</code>) repeats for every assessed app. PBI rejects <code>*:1</code> cardinality on the bridges and shows &quot;control_id contains duplicate value GDPR_Art_5&quot;. Set all four bridge relationships to <strong><code>Viele-zu-Viele (*:*)</code></strong>:</p><table tabindex="0"><thead><tr><th>From</th><th>To</th><th>KardinalitÃ¤t</th><th>Kreuzfilter</th></tr></thead><tbody><tr><td><code>link_control_signal[control_id]</code></td><td><code>fact_controls[control_id]</code></td><td><code>*:*</code></td><td>Einfach</td></tr><tr><td><code>link_control_signal[signal_id]</code></td><td><code>fact_signals[signal_id]</code></td><td><code>*:*</code></td><td>Einfach</td></tr><tr><td><code>link_signal_evidence[signal_id]</code></td><td><code>fact_signals[signal_id]</code></td><td><code>*:*</code></td><td>Einfach</td></tr><tr><td><code>link_signal_evidence[evidence_id]</code></td><td><code>dim_evidence[evidence_id]</code></td><td><code>*:1</code></td><td><strong>Beide</strong></td></tr></tbody></table><p>The yellow &quot;begrenzte Beziehung&quot; warnings on M:M edges are expected; they signal limited-relationship semantics, which is what we want.</p><h3 id="adaptation-b-evidence-url-lives-on-link-signal-evidence-0269" tabindex="-1">Adaptation B -- evidence_url lives on link_signal_evidence (#0269) <a class="header-anchor" href="#adaptation-b-evidence-url-lives-on-link-signal-evidence-0269" aria-label="Permalink to &quot;Adaptation B -- evidence_url lives on link_signal_evidence (#0269)&quot;">​</a></h3><p>Portfolio <code>dim_evidence</code> is deduplicated across apps and has <strong>no</strong><code>app_id</code> column. <code>link_signal_evidence</code> carries <code>signal_id, evidence_id, app_id</code>, so the URL construction happens there:</p><ol><li>Power Query Editor &gt; select <code>link_signal_evidence</code>.</li><li><code>Start &gt; Abfragen kombinieren &gt; Abfragen zusammenfÃ¼hren</code> -&gt; merge with <code>dim_evidence</code> on <code>evidence_id</code> (Linker Ã¤uÃŸerer Join).</li><li>Expand the merged column, picking only <code>source_path</code> (uncheck the prefix option to land it as a clean column name).</li><li><code>Spalte hinzufÃ¼gen &gt; Benutzerdefinierte Spalte</code>: <ul><li>Name: <code>evidence_url</code></li><li>Formula (v0.1.7+ bundles per #0267 emitter normalisation):<div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>= EvidenceUrlPrefix</span></span>
<span class="line"><span>  &amp; [app_id]</span></span>
<span class="line"><span>  &amp; &quot;/&quot;</span></span>
<span class="line"><span>  &amp; Text.Replace([source_path], &quot;\\&quot;, &quot;/&quot;)</span></span></code></pre></div></li><li>Legacy formula (pre-v0.1.7 bundles where <code>source_path</code> may still drop the <code>wsp/inputs/</code> prefix on file rows):<div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>= EvidenceUrlPrefix</span></span>
<span class="line"><span>  &amp; [app_id]</span></span>
<span class="line"><span>  &amp; &quot;/&quot;</span></span>
<span class="line"><span>  &amp; Text.Replace(</span></span>
<span class="line"><span>      if Text.StartsWith([source_path], &quot;wsp/&quot;)</span></span>
<span class="line"><span>        then [source_path]</span></span>
<span class="line"><span>        else &quot;wsp/inputs/&quot; &amp; [source_path],</span></span>
<span class="line"><span>      &quot;\\&quot;, &quot;/&quot;)</span></span></code></pre></div></li></ul></li><li><code>SchlieÃŸen &amp; Ã¼bernehmen</code>.</li><li>In Report view, select <code>evidence_url</code> and set <code>Spaltentools &gt; Datenkategorie &gt; Web-URL</code>.</li></ol><p><strong><code>EvidenceUrlPrefix</code> parameter:</strong> Type <code>Text</code>, value <code>file:///C:/swao-e2e/apps/</code> (ends at <code>apps/</code> -- no app_id baked in, because the formula adds <code>[app_id]</code> per row). Post-publish: change to <code>https://accenture.sharepoint.com/sites/swao/apps/</code> or similar.</p><p>Supporting Evidence Tabelle uses <code>link_signal_evidence[evidence_url]</code> instead of <code>dim_evidence[evidence_link]</code>. One row per (signal, evidence) pair, which matches the master/detail filter context.</p><h3 id="adaptation-c-defensive-measures-that-handle-ghostfolio-style-apps" tabindex="-1">Adaptation C -- defensive measures that handle ghostfolio-style apps <a class="header-anchor" href="#adaptation-c-defensive-measures-that-handle-ghostfolio-style-apps" aria-label="Permalink to &quot;Adaptation C -- defensive measures that handle ghostfolio-style apps&quot;">​</a></h3><p>Apps assessed without the LLM <code>comp</code> pass produce <code>BLANK</code> for several audit measures. CF rules-based formatting does not match BLANK (BLANK is not a number, so <code>&gt;= -1</code> is false). To make BLANK render as 0 and pick up the green CF, wrap measures with <code>+ 0</code> or COALESCE:</p><div class="language-dax vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dax</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Negative</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Signals</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> CALCULATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">COUNTROWS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&#39;fact_signals&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&#39;fact_signals&#39;[outcome]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;negative&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">FP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Consideration</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> DIVIDE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">[FPs Considered]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">[Total Signals]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre></div><p>This makes the &quot;under-assessed&quot; apps visible in the dashboard with honest-zero values rather than blank cells.</p><h3 id="known-portfolio-specific-limitations" tabindex="-1">Known portfolio-specific limitations <a class="header-anchor" href="#known-portfolio-specific-limitations" aria-label="Permalink to &quot;Known portfolio-specific limitations&quot;">​</a></h3><ul><li><strong>signal_id as a fourth row level on the matrix triggers InvalidUnconstrainedJoin</strong> -- same as on swao-report. Master/detail is the canonical workaround; pin the matrix at <code>app &gt; regime &gt; control</code> and let the Supporting Evidence Tabelle carry the signal context via cross-filter.</li><li><strong>fact_controls has no GAP rows</strong> when only PARTIAL/UNKNOWN verdicts were produced. Use <code>fact_app_heatmap[gap_score]</code> (the severity-weighted risk score) for the Heatmap matrix and KPI cards instead of literal GAP counts.</li></ul><hr><h2 id="_0-prerequisites" tabindex="-1">0. Prerequisites <a class="header-anchor" href="#_0-prerequisites" aria-label="Permalink to &quot;0. Prerequisites&quot;">​</a></h2><p>Same as the single-app guide, with one addition: the <code>star/</code> bundle must be a portfolio bundle at <code>&lt;workspace&gt;/wsp/exports/&lt;ts&gt;/star/</code> (symmetric dual-wsp, #0230), not a per-app bundle. The portfolio bundle has the same 17 single-app tables PLUS:</p><ul><li><code>fact_app_heatmap.csv</code> (one row per app x regime; outcome counts + gap_score)</li><li><code>fact_app_summary.csv</code> (one row per app; 7R, scores, totals)</li></ul><p>= 19 CSV files total in the portfolio star/ directory.</p><p>Generate one with:</p><pre><code>swao export --portfolio    # Premium-gated
</code></pre><p>Or use the test fixture in <code>export-portfolio.test.ts</code> and copy the emitted <code>wsp/exports/&lt;ts&gt;/star/</code> somewhere durable.</p><hr><h2 id="_1-3-initial-setup" tabindex="-1">1-3. Initial setup <a class="header-anchor" href="#_1-3-initial-setup" aria-label="Permalink to &quot;1-3. Initial setup&quot;">​</a></h2><p>Follow steps 1-3 of the single-app guide, but:</p><ul><li><p>Parameter name: <code>SWAOPortfolioExportPath</code></p></li><li><p>Parameter description: &quot;Absolute path to the SWAO portfolio <code>star/</code> directory inside <code>&lt;workspace&gt;/wsp/exports/&lt;ts&gt;/</code>.&quot;</p></li><li><p>The <code>Get Data &gt; Folder</code> step picks up 19 files instead of 17.</p></li><li><p>The two extra tables (<code>fact_app_heatmap</code>, <code>fact_app_summary</code>) need numeric column typing:</p><table tabindex="0"><thead><tr><th>Table</th><th>Numeric columns</th></tr></thead><tbody><tr><td><code>fact_app_heatmap</code></td><td><code>satisfied_count</code>, <code>partial_count</code>, <code>gap_count</code>, <code>unknown_count</code>, <code>n_a_count</code>, <code>gap_score</code></td></tr><tr><td><code>fact_app_summary</code></td><td><code>portability_score</code>, <code>coverage_score</code>, <code>total_negative_signals</code>, <code>weighted_risk_score</code></td></tr></tbody></table></li></ul><hr><h2 id="_4-relationships" tabindex="-1">4. Relationships <a class="header-anchor" href="#_4-relationships" aria-label="Permalink to &quot;4. Relationships&quot;">​</a></h2><p>Same as the single-app template, plus:</p><table tabindex="0"><thead><tr><th>From</th><th>Column</th><th>To</th><th>Column</th></tr></thead><tbody><tr><td>fact_app_heatmap</td><td>app_id</td><td>dim_app</td><td>app_id</td></tr><tr><td>fact_app_heatmap</td><td>regime_id</td><td>dim_regime</td><td>regime_id</td></tr><tr><td>fact_app_summary</td><td>app_id</td><td>dim_app</td><td>app_id</td></tr></tbody></table><p>The portfolio template differs from single-app in that <strong>most filters flow from <code>dim_app</code></strong>. The hierarchical slicer <code>business_domain -&gt; business_criticality -&gt; app_id</code> lives at the report level (so every page inherits it).</p><hr><h2 id="_5-dax-measures" tabindex="-1">5. DAX measures <a class="header-anchor" href="#_5-dax-measures" aria-label="Permalink to &quot;5. DAX measures&quot;">​</a></h2><p>Carry over the single-app measures, plus:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total Apps = COUNTROWS(&#39;dim_app&#39;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Apps With Critical Risk =</span></span>
<span class="line"><span>  CALCULATE([Total Apps], &#39;fact_app_summary&#39;[weighted_risk_score] &gt;= 10)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Average Coverage =</span></span>
<span class="line"><span>  AVERAGE(&#39;fact_app_summary&#39;[coverage_score])</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Top Risk App =</span></span>
<span class="line"><span>  CALCULATE(</span></span>
<span class="line"><span>    SELECTEDVALUE(&#39;dim_app&#39;[app_id]),</span></span>
<span class="line"><span>    TOPN(1, &#39;fact_app_summary&#39;,</span></span>
<span class="line"><span>      &#39;fact_app_summary&#39;[weighted_risk_score], DESC)</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Negative Signals (Portfolio) =</span></span>
<span class="line"><span>  SUM(&#39;fact_app_summary&#39;[total_negative_signals])</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Weighted Risk (Portfolio) =</span></span>
<span class="line"><span>  SUM(&#39;fact_app_summary&#39;[weighted_risk_score])</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Apps By 7R =</span></span>
<span class="line"><span>  COUNTROWS(&#39;dim_app&#39;)   -- group by [seven_r_label] in visuals</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Portfolio Coverage Distribution =</span></span>
<span class="line"><span>  -- bucket apps by coverage_score; used in histogram on Page 1</span></span>
<span class="line"><span>  SWITCH(</span></span>
<span class="line"><span>    TRUE(),</span></span>
<span class="line"><span>    &#39;fact_app_summary&#39;[coverage_score] &gt;= 0.9, &quot;0.9-1.0&quot;,</span></span>
<span class="line"><span>    &#39;fact_app_summary&#39;[coverage_score] &gt;= 0.8, &quot;0.8-0.9&quot;,</span></span>
<span class="line"><span>    &#39;fact_app_summary&#39;[coverage_score] &gt;= 0.7, &quot;0.7-0.8&quot;,</span></span>
<span class="line"><span>    &quot;&lt;0.7&quot;</span></span>
<span class="line"><span>  )</span></span></code></pre></div><hr><h2 id="_6-report-pages" tabindex="-1">6. Report pages <a class="header-anchor" href="#_6-report-pages" aria-label="Permalink to &quot;6. Report pages&quot;">​</a></h2><p>Six pages, slightly different from single-app:</p><h3 id="page-1-portfolio-overview" tabindex="-1">Page 1: Portfolio Overview <a class="header-anchor" href="#page-1-portfolio-overview" aria-label="Permalink to &quot;Page 1: Portfolio Overview&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Card</td><td><code>[Total Apps]</code></td><td>&quot;Apps in portfolio&quot;</td></tr><tr><td>Donut</td><td>Legend: <code>dim_app[seven_r_label]</code>. Values: <code>[Total Apps]</code></td><td>&quot;7R distribution&quot;</td></tr><tr><td>Gauge</td><td><code>[Average Coverage]</code></td><td>format %, target 0.85</td></tr><tr><td>Strip</td><td>Rows: <code>dim_regime[regime_id]</code>. Columns: <code>dim_app[app_id]</code>. Values: count</td><td>&quot;Regime coverage strip&quot;</td></tr><tr><td>Table</td><td>top 10 by <code>[Weighted Risk (Portfolio)]</code></td><td>&quot;Top apps by risk&quot;</td></tr></tbody></table><h3 id="page-2-app-heatmap" tabindex="-1">Page 2: App Heatmap <a class="header-anchor" href="#page-2-app-heatmap" aria-label="Permalink to &quot;Page 2: App Heatmap&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Matrix</td><td>Rows: <code>dim_app[app_id]</code>. Columns: <code>dim_regime[regime_id]</code>. Values: <code>fact_app_heatmap[gap_score]</code></td><td>Conditional colour: green=0, amber&lt;5, red&gt;=5</td></tr><tr><td>Slicer</td><td><code>dim_app[business_domain]</code>, <code>[business_criticality]</code>, <code>[app_id]</code> (hierarchical)</td><td></td></tr><tr><td>Slicer</td><td><code>dim_app[seven_r_label]</code></td><td></td></tr><tr><td>Drill-through</td><td>-&gt; Compliance page filtered by selected (app, regime)</td><td></td></tr></tbody></table><h3 id="page-3-compliance" tabindex="-1">Page 3: Compliance <a class="header-anchor" href="#page-3-compliance" aria-label="Permalink to &quot;Page 3: Compliance&quot;">​</a></h3><p>Largely identical to the single-app Compliance page but with <code>app_id</code> filter at the top so consultants can switch between apps.</p><h3 id="page-4-risk-and-7r" tabindex="-1">Page 4: Risk and 7R <a class="header-anchor" href="#page-4-risk-and-7r" aria-label="Permalink to &quot;Page 4: Risk and 7R&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Table</td><td><code>dim_app[app_id]</code>, <code>[seven_r_label]</code>, <code>[portability_score]</code>, <code>fact_app_summary[total_negative_signals]</code>, <code>[weighted_risk_score]</code></td><td>Sort by <code>weighted_risk_score</code> desc</td></tr><tr><td>Spotlight (card)</td><td>top 3 apps by <code>[Weighted Risk (Portfolio)]</code></td><td></td></tr></tbody></table><h3 id="page-5-wave-sequencing-tier-2-stub" tabindex="-1">Page 5: Wave Sequencing (Tier-2 stub) <a class="header-anchor" href="#page-5-wave-sequencing-tier-2-stub" aria-label="Permalink to &quot;Page 5: Wave Sequencing (Tier-2 stub)&quot;">​</a></h3><p>When <code>fact_wave_sequence</code> rows == 0 (i.e. before #0068 closes), this page renders an empty-state card with the text:</p><blockquote><p>Wave sequencing requires the Tier 2 portfolio rollup schema (#0068), which lands post-PoC. Drop your dependency CSVs into <code>apps/&lt;id&gt;/imports/</code> and run <code>swao aggregate</code> once the feature ships. SPEC Â§24.1.</p></blockquote><p>After #0068:</p><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Gantt</td><td>X: <code>fact_wave_sequence[target_quarter]</code>. Y: <code>dim_app[app_id]</code></td><td>grouped by wave_number</td></tr><tr><td>Network</td><td>source: <code>fact_app_dependencies[app_id]</code>. target: <code>[depends_on_app_id]</code></td><td>dependency overlay</td></tr></tbody></table><h3 id="page-6-auditor-roll-up" tabindex="-1">Page 6: Auditor Roll-up <a class="header-anchor" href="#page-6-auditor-roll-up" aria-label="Permalink to &quot;Page 6: Auditor Roll-up&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Table</td><td><code>dim_app[app_id]</code>, <code>[Rationale Coverage]</code>, <code>[FP Consideration Rate]</code>, <code>[Total Signals]</code>, <code>[Negative Signals]</code></td><td>Conditional colour on coverage %</td></tr></tbody></table><h3 id="page-7-signals-drill-down-v1-2-0251" tabindex="-1">Page 7: Signals drill-down (v1.2, #0251) <a class="header-anchor" href="#page-7-signals-drill-down-v1-2-0251" aria-label="Permalink to &quot;Page 7: Signals drill-down (v1.2, #0251)&quot;">​</a></h3><p>Auditor traceability gap closer for portfolio scope. Two visuals on a new page:</p><h4 id="visual-a-per-app-severity-matrix" tabindex="-1">Visual A -- per-app severity matrix <a class="header-anchor" href="#visual-a-per-app-severity-matrix" aria-label="Permalink to &quot;Visual A -- per-app severity matrix&quot;">​</a></h4><ul><li><strong>Type:</strong> Matrix.</li><li><strong>Rows:</strong> <code>dim_app[app_id]</code>.</li><li><strong>Columns:</strong> <code>fact_signals[severity]</code> (custom sort: <code>critical, high, medium, low, informational</code>).</li><li><strong>Values:</strong> measure <code>[Total Signals] = COUNTROWS(fact_signals)</code>.</li><li><strong>Conditional formatting</strong> on cell background by signal count (gradient white -&gt; red).</li><li><strong>Title:</strong> &quot;Signals per app by severity&quot;.</li></ul><h4 id="visual-b-cross-app-drill-down-table" tabindex="-1">Visual B -- cross-app drill-down table <a class="header-anchor" href="#visual-b-cross-app-drill-down-table" aria-label="Permalink to &quot;Visual B -- cross-app drill-down table&quot;">​</a></h4><ul><li><strong>Type:</strong> Table.</li><li><strong>Columns:</strong> <code>fact_signals[signal_id]</code>, <code>[app_id]</code>, <code>[severity]</code>, <code>[outcome]</code>, <code>[derivation]</code> (truncated), <code>[assessor]</code>.</li><li><strong>Cross-filter:</strong> Visual A&#39;s matrix selection. Click a cell in the matrix -&gt; the table scopes to those signals.</li><li><strong>Sort:</strong> severity desc, then signal_id asc.</li><li><strong>Title:</strong> &quot;Drill-down -- click a matrix cell to filter&quot;.</li></ul><h3 id="page-2-update-measure-boolean-comparison-v1-2-0250-pbit-half" tabindex="-1">Page 2 update -- measure boolean comparison (v1.2, #0250 .pbit half) <a class="header-anchor" href="#page-2-update-measure-boolean-comparison-v1-2-0250-pbit-half" aria-label="Permalink to &quot;Page 2 update -- measure boolean comparison (v1.2, #0250 .pbit half)&quot;">​</a></h3><p>The code half of #0250 (Sprint 028 v0.0.32+) emits literal JS booleans for <code>fact_signals[synthesis]</code> and <code>fact_signals[false_positive_considered]</code> instead of strings. The portfolio template&#39;s measures must match.</p><p>Open the <code>_Measures</code> table and audit every measure that compares against <code>synthesis</code> or <code>false_positive_considered</code>. The change pattern:</p><table tabindex="0"><thead><tr><th>Before (v1.1)</th><th>After (v1.2)</th></tr></thead><tbody><tr><td><code>... synthesis = &quot;true&quot;</code></td><td><code>... synthesis = TRUE()</code></td></tr><tr><td><code>... false_positive_considered = &quot;true&quot;</code></td><td><code>... false_positive_considered = TRUE()</code></td></tr></tbody></table><p>Specifically, audit <code>[FP Consideration Rate]</code>, <code>[Synthesis Coverage]</code>, and any custom measure derived from these columns. Re-bind to boolean literals; the cells now render as <code>TRUE</code> / <code>FALSE</code> (capitalised) in PowerBI.</p><p><strong>Why this matters:</strong> v1.1 measures silently returned 0% because <code>&quot;true&quot; = TRUE()</code> is false in DAX. The auditor card &quot;FP Consideration Rate&quot; was showing 0% on bundles that actually had FP-considered signals.</p><h3 id="conditional-formatting-reload-workaround-v1-2-0250-portfolio-half" tabindex="-1">Conditional formatting reload workaround (v1.2, #0250 portfolio half) <a class="header-anchor" href="#conditional-formatting-reload-workaround-v1-2-0250-portfolio-half" aria-label="Permalink to &quot;Conditional formatting reload workaround (v1.2, #0250 portfolio half)&quot;">​</a></h3><p>Sprint 028 audit (<code>reports/0028-Audit-E2E-Solution.md</code>) noticed that some conditional-formatting rules survive <code>.pbit</code> save but unbind on fresh-Desktop reload. Reproduce + workaround:</p><ol><li>Open the saved <code>.pbit</code> in a fresh PowerBI Desktop.</li><li>Paste the export path; let the data load.</li><li>Click each visual that should have CF (Risks card, Auditor coverage cards, &quot;Apps With Critical Risk&quot; gauge); confirm colours render as authored.</li><li><strong>If colour rules unbind</strong>, the symptom is white cells where the author intended green / amber / red.</li><li><strong>Workaround</strong>: re-author the CF in the live session, save again as <code>.pbit</code>, repeat the smoke. The second save is the persistent one. Document any rule that needed re-binding in <code>REFRESH-RUNBOOK.md</code>.</li></ol><p>Root cause is not fully understood (PowerBI bug suspected -- format strings stored separately from rule references). Workaround is sufficient for v1.2 ship.</p><hr><h2 id="_7-cross-template-navigation" tabindex="-1">7. Cross-template navigation <a class="header-anchor" href="#_7-cross-template-navigation" aria-label="Permalink to &quot;7. Cross-template navigation&quot;">​</a></h2><p>Add a button on Page 1 (Portfolio Overview) labelled &quot;Open per-app dashboard&quot;. The button&#39;s URL action is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;file:///&quot; &amp; &#39;dim_app&#39;[app_id] &amp; &quot;/wsp/exports/latest/templates/swao-report.pbit&quot;</span></span></code></pre></div><p>Note: PowerBI&#39;s URL action requires file:// scheme. In practice, the consultant clicks the row, copies the path, and opens the .pbit manually. This is the documented limitation per design 019 Â§13.4.</p><hr><h2 id="_8-12-save-smoke-test-version-troubleshoot" tabindex="-1">8-12. Save, smoke-test, version, troubleshoot <a class="header-anchor" href="#_8-12-save-smoke-test-version-troubleshoot" aria-label="Permalink to &quot;8-12. Save, smoke-test, version, troubleshoot&quot;">​</a></h2><p>Identical to the single-app guide. Place the saved template at <code>swao/docs/templates/powerbi/swao-portfolio.pbit</code>.</p><hr><h2 id="_13-empty-state-polish" tabindex="-1">13. Empty-state polish <a class="header-anchor" href="#_13-empty-state-polish" aria-label="Permalink to &quot;13. Empty-state polish&quot;">​</a></h2><p>The Wave Sequencing page (Page 5) MUST render gracefully with zero rows in <code>fact_wave_sequence</code>. Verify by:</p><ol><li>Loading the template against the test fixture from <code>export-portfolio.test.ts</code> (which has zero <code>fact_wave_sequence</code> rows).</li><li>Confirming the page shows the empty-state card, not red error indicators.</li><li>Re-loading against a future bundle that has real <code>fact_wave_sequence</code> rows; the Gantt + network visuals should populate.</li></ol><hr><h2 id="_14-reference" tabindex="-1">14. Reference <a class="header-anchor" href="#_14-reference" aria-label="Permalink to &quot;14. Reference&quot;">​</a></h2><ul><li>ADR-0026 amendment 2026-05-09 (portfolio mode)</li><li>Design 019 Â§13 (portfolio mode spec)</li><li><code>src/exports/star.ts::writePortfolioStarExport</code> (canonical bundle shape)</li><li>This guide&#39;s single-app sibling: <code>swao-report.pbit</code> -- <code>AUTHORING-GUIDE.md</code></li></ul>`,91)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
